svg.script:
var _tip=null;
function tF(id){
  var t=document.getElementById('tip-'+id);
  if(_tip&&_tip!==t)_tip.setAttribute('display','none');
  if(!t)return;
  var v=t.getAttribute('display')==='none';
  t.setAttribute('display',v?'inline':'none');
  _tip=v?t:null;
}
var _origH=1712;
var _paths=[
  {id:'path-cache',h:214},
  {id:'path-default',h:424}
];
function selectPath(name){
  if(_tip){_tip.setAttribute('display','none');_tip=null;}
  var svg=document.querySelector('svg');
  var altR=document.getElementById('alt-rect');
  var ba=document.getElementById('below-alt');
  var origAltH=660;
  if(name==='all'){
    _paths.forEach(function(p){
      var g=document.getElementById(p.id);
      g.setAttribute('display','inline');
      g.setAttribute('transform','');
    });
    altR.setAttribute('height',String(origAltH));
    ba.setAttribute('transform','');
    svg.setAttribute('height',_origH);
    svg.setAttribute('viewBox','0 0 800 '+_origH);
    hlTab('all');return;
  }
  var hidAbove=0,totalHid=0,found=false;
  _paths.forEach(function(p){
    var g=document.getElementById(p.id);
    var k=p.id.replace('path-','');
    if(k===name){found=true;g.setAttribute('display','inline');g.setAttribute('transform','translate(0,'+(-hidAbove)+')');}
    else{g.setAttribute('display','none');if(!found)hidAbove+=p.h;totalHid+=p.h;}
  });
  var sel;_paths.forEach(function(p){if(p.id==='path-'+name)sel=p;});
  altR.setAttribute('height',String(sel.h+30));
  ba.setAttribute('transform','translate(0,'+(-totalHid)+')');
  var newH=_origH-totalHid;
  svg.setAttribute('height',newH);
  svg.setAttribute('viewBox','0 0 800 '+newH);
  hlTab(name);
}
function hlTab(name){
  ['all','cache','default'].forEach(function(k){
    var r=document.getElementById('tab-'+k);
    if(!r)return;
    if(k===name){r.setAttribute('stroke-width','1.5');r.setAttribute('opacity','1');}
    else{r.setAttribute('stroke-width','0.8');r.setAttribute('opacity','0.5');}
  });
}
document.addEventListener('click',function(e){
  if(e.target.closest&&(e.target.closest('.fn')||e.target.closest('.tab')))return;
  if(_tip){_tip.setAttribute('display','none');_tip=null;}
});
